private enum AmazonScreenFactory {
    @ViewBuilder
    static func screen(for tab: String) -> some View {
        switch tab.lowercased() {
        case let t where t.contains("accueil") || t.contains("home") || t.contains("search") || t.contains("recherch"):
            AmazonShopScreen()
        default:
            AmazonGenericListScreen(title: tab)
        }
    }
}
