private struct AmazonShopScreen: View {
    var body: some View {
        NavigationStack {
            ScrollView {
                VStack(spacing: 16) {
                    HStack {
                        Image(systemName: "magnifyingglass")
                        Text("Rechercher sur Amazon").foregroundStyle(.secondary)
                        Spacer(); Image(systemName: "camera")
                    }.padding().background(RoundedRectangle(cornerRadius: 8).fill(Color(.systemGray6))).padding(.horizontal)
                    LazyVGrid(columns: [GridItem(.flexible()), GridItem(.flexible())], spacing: 12) {
                        ForEach(AmazonDemoData.products) { prod in AmazonProductTile(product: prod, accent: AmazonTokens.amzBuyNowOrange) }
                    }.padding(.horizontal)
                }
            }.background(AmazonTokens.amzCanvas.ignoresSafeArea()).navigationTitle("Amazon")
        }
    }
}

private struct AmazonProductTile: View {
    let product: AmazonProduct; let accent: Color
    var body: some View {
        VStack(alignment: .leading, spacing: 6) {
            RoundedRectangle(cornerRadius: 8).fill(product.color.opacity(0.2)).aspectRatio(1, contentMode: .fit)
            Text(product.title).font(.caption).lineLimit(2)
            Text(product.price).font(.subheadline.bold()).foregroundStyle(accent)
        }
    }
}

private struct AmazonProduct: Identifiable { let id = UUID(); let title: String; let price: String; let color: Color }
